mapper.select:
  		SELECT s.num AS surveyNum, s.sub AS surveySub, s.code AS surveyCode, s.sdate AS surveyDate,
			sc.surveytype AS surveytype, sc.subcode AS subCode, sc.surveytitle AS surveytitle, sc.surveycnt AS surveycnt
		FROM SURVEY s, SURVEYCONTENT sc WHERE s.num = sc.SUBCODE AND s.num = #{num}
